import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetAutoFlush_DefaultFalse() throws Exception {
        CSVFormat format = getCSVFormatWithAutoFlush(false);
        boolean autoFlush = format.getAutoFlush();
        assertFalse(autoFlush);
    }

    @Test
    void testGetAutoFlush_True() throws Exception {
        CSVFormat format = getCSVFormatWithAutoFlush(true);
        boolean autoFlush = format.getAutoFlush();
        assertTrue(autoFlush);
    }

    private CSVFormat getCSVFormatWithAutoFlush(boolean value) throws Exception {
        // Create a CSVFormat instance using the public DEFAULT instance and modify the private final autoFlush field via reflection
        CSVFormat format = CSVFormat.DEFAULT;
        Field autoFlushField = CSVFormat.class.getDeclaredField("autoFlush");
        autoFlushField.setAccessible(true);

        // Remove final modifier to allow modification of final field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(autoFlushField, autoFlushField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        autoFlushField.set(format, value);
        return format;
    }
}
